/// Extracts the first grapheme cluster of the string.
/// Fails with an error if the string is empty.
#[func]
pub fn first(
    &self,
    /// Number of times to repeat this operation. Fails if exceeds string length.
    #[named]
    #[default(1)]
    repeat: usize,
) -> StrResult<Str> {
    if self.0.is_empty() {
        return Err(string_is_empty());
    }
    let clusters: Vec<&str> = self.0.graphemes(true).take(repeat).collect();
    if clusters.len() < repeat {
        return Err(not_enough_graphemes(repeat, clusters.len()));
    }
    Ok(clusters.concat().into())
}

/// Extracts the last grapheme cluster of the string.
/// Fails with an error if the string is empty.
#[func]
pub fn last(
    &self,
    /// Number of times to repeat this operation. Fails if exceeds string length.
    #[named]
    #[default(1)]
    repeat: usize,
) -> StrResult<Str> {
    if self.0.is_empty() {
        return Err(string_is_empty());
    }
    let mut collected: Vec<&str> = self.0.graphemes(true).rev().take(repeat).collect();
    if collected.len() < repeat {
        return Err(not_enough_graphemes(repeat, collected.len()));
    }
    collected.reverse();
    Ok(collected.concat().into())
}

